chunks: list[str] = []
meta: dict[str, Any] = {"model": model}  # real model id if pinned, else unknown
result_error: dict[str, Any] | None = None

async def _drain():
    nonlocal result_error
    async for msg in query(prompt=prompt, options=opts):
        # The SDK may emit a first-class RateLimitEvent (status='rejected')
        # ahead of / instead of a ResultMessage error — treat it as a rate
        # window so the long backpressure path runs, not fast retry (#266).
        if type(msg).__name__ == "RateLimitEvent" or getattr(msg, "status", None) == "rejected":
            result_error = {"status": 429, "errors": ["RateLimitEvent"], "stop_reason": "rate_limit"}
            continue
        if isinstance(msg, AssistantMessage):
            if getattr(msg, "model", None):
                meta["model"] = msg.model  # the actual model the run used (#204)
            for block in msg.content:
                if isinstance(block, TextBlock):
                    chunks.append(block.text)
        elif isinstance(msg, ResultMessage):
            if getattr(msg, "usage", None):
                meta["usage"] = msg.usage  # token usage for the span (#203)
            if getattr(msg, "total_cost_usd", None) is not None:
                meta["cost_usd"] = msg.total_cost_usd
            # The CLI reports API failures (incl. rate windows) by COMPLETING
            # the stream with is_error=True / api_error_status set, NOT by
            # raising. Capture it so a failed run is not returned as success
            # (pass-4 #1).
            if getattr(msg, "is_error", False):
                result_error = {
                    "status": getattr(msg, "api_error_status", None),
                    "errors": getattr(msg, "errors", None),
                    "stop_reason": getattr(msg, "stop_reason", None),
                }

await asyncio.wait_for(_drain(), timeout=T3_TIMEOUT)

if result_error is not None:
    status = result_error.get("status")
    detail = result_error.get("errors") or result_error.get("stop_reason") or status
    if status in (429, 529):
        raise RateLimitError(f"Tier 3 rate window (api_error_status={status}): {detail}")
    if status in (401, 403):
        raise PermanentReasoningError(f"Tier 3 auth failure ({status}): {detail}")
    raise ReasoningError(f"Tier 3 run reported an error (status={status}): {detail}")

return "".join(chunks).strip(), meta

def _t2_complete(prompt: str, system: str | None, temperature: float, model: str,
                 json_mode: bool) -> tuple[str, dict[str, Any]]:
    llm = _ollama(model, temperature, json_mode)
    messages: list[tuple[str, str]] = []
    if system:
        messages.append(("system", system))
    messages.append(("human", prompt))

    def _call():
        resp = llm.invoke(messages)
        content = getattr(resp, "content", resp)
        text = content if isinstance(content, str) else str(content)
        return text, getattr(resp, "usage_metadata", None)  # token counts (#279)

    try:
        # Give the outer future timeout margin over the inner HTTP timeout
        # (client_kwargs timeout == T2_TIMEOUT) so the inner socket timeout wins and
        # the worker self-terminates cleanly, instead of racing exactly and risking
        # an abandoned (leaked) worker — mirrors the T3_TIMEOUT + 30 backstop (#272).
        text, usage = _with_timeout(
            _call, T2_TIMEOUT + 10, f"Tier 2 (Ollama @ {T2_BASE_URL})"
        )
        text = text.strip()
        if not text:
            # An empty/whitespace reply is not a valid result — surface it as a
            # retryable error rather than silently returning "" and corrupting a
            # JSON caller or recording an empty high-stakes answer (#233).
            raise ReasoningError(f"Tier 2 (Ollama @ {T2_BASE_URL}) returned an empty reply")
        return text, {"model": model, "usage": usage}
    except ReasoningError:
        raise
    except Exception as exc:
        msg = str(exc).lower()
        # A missing model is permanent — retrying just wastes backoff (#194).
        if "not found" in msg or "no such model" in msg or "try pulling" in msg:
            raise PermanentReasoningError(
                f"Tier 2 model {model!r} not available on Ollama: {exc}"
            ) from exc
        raise ReasoningError(f"Tier 2 (Ollama @ {T2_BASE_URL}) call failed: {exc}") from exc

